
import React, {type FunctionComponent} from 'react'
import type {
    IWidgetBarIncomingProp,
    IWidgetDoughnutIncomingProp,
    IWidgetLineIncomingProp,
    IWidgetPieIncomingProp,
    IWidgetPolarAreaIncomingProp,
    IWidgetRadarIncomingProp
} from '@lmb/kitsconcerto-types'


const Widgets = (props:any) => {
  return null
}

export const Bar: FunctionComponent<Omit<IWidgetBarIncomingProp, 'type' | 'colors' | 'isDarkMode'>> = props => {
  return <Widgets {...props} type={'BarChart'} />
}
export const Line: FunctionComponent<Omit<IWidgetLineIncomingProp, 'type' | 'colors' | 'isDarkMode'>> = props => {
  return <Widgets {...props} type={'LineChart'} />
}
export const Pie: FunctionComponent<Omit<IWidgetPieIncomingProp, 'type' | 'colors' | 'isDarkMode'>> = props => {
  return <Widgets {...props} type={'PieChart'} />
}
export const Radar: FunctionComponent<Omit<IWidgetRadarIncomingProp, 'type' | 'colors' | 'isDarkMode'>> = props => {
  return <Widgets {...props} type={'RadarChart'} />
}
export const PolarArea: FunctionComponent<Omit<IWidgetPolarAreaIncomingProp, 'type' | 'colors' | 'isDarkMode'>> = props => {
  return <Widgets {...props} type={'PolarAreaChart'} />
}
export const Doughnut: FunctionComponent<
  Omit<IWidgetDoughnutIncomingProp, 'type' | 'colors' | 'isDarkMode'>
> = props => {
  return <Widgets {...props} type={'DoughnutChart'} />
}
